let pendingActionsSnoozed = false;

function notifyAdmins(store, { type, msg, date }) {
  const d = date || todayStr();
  (store.users || [])
    .filter((u) => u.active && (u.role === "admin" || u.role === "manager"))
    .forEach((a) => {
      store.notifications.push({ id: uid(), userId: a.id, type, msg, read: false, date: d });
    });
}

