const uid  = () => Math.random().toString(36).slice(2,10);
const todayStr = () => new Date().toISOString().split("T")[0];
const nowStr   = () => {
  const n = new Date();
  return `${String(n.getHours()).padStart(2,"0")}:${String(n.getMinutes()).padStart(2,"0")}`;
};
const fmt12 = (t24) => {
  if (!t24) return "—";
  const [h,m] = t24.split(":").map(Number);
  const ampm = h >= 12 ? "PM" : "AM";
  const h12  = h % 12 || 12;
  return `${h12}:${String(m).padStart(2,"0")} ${ampm}`;
};
const fmtDate = (d) => { if(!d) return "—"; return new Date(d).toLocaleDateString("en-PK",{day:"2-digit",month:"short",year:"numeric"}); };
const fmtPKR  = (n) => `PKR ${Number(n||0).toLocaleString()}`;
const calcTotal = (s) => (s?.basic||0)+(s?.hra||0)+(s?.transport||0)+(s?.medical||0);
const calcTenure = (j) => {
  if(!j) return "—";
  const diff = Date.now()-new Date(j).getTime();
  const y=Math.floor(diff/(1000*60*60*24*365)), m=Math.floor((diff%(1000*60*60*24*365))/(1000*60*60*24*30));
  return y>0?`${y}y ${m}m`:`${m}m`;
};
const getDatesInRange = (from, to) => {
  const dates=[], cur=new Date(from), end=new Date(to);
  while(cur<=end){ dates.push(cur.toISOString().split("T")[0]); cur.setDate(cur.getDate()+1); }
  return dates;
};
const leaveDatesOf = (l) => {
  if (l.dates?.length) return l.dates;
  if (l.dateFrom && l.dateTo) return getDatesInRange(l.dateFrom, l.dateTo);
  if (l.dateFrom) return [l.dateFrom];
  return [];
};
