const useNav   = () => useContext(NavTargetCtx);

function useApplyNavTarget(page, setTab){
  const { navTarget, clearNav } = useNav();
  useEffect(() => {
    if (!navTarget || navTarget.page !== page) return;
    if (navTarget.tab && setTab) setTab(navTarget.tab);
    scrollToTarget(navTarget.targetId);
    clearNav();
  }, [navTarget, page]);
}

function ConfirmModal({ open, title, message, onConfirm, onCancel, confirmLabel = "Confirm", danger = false }) {
  const { tk } = useTheme();
  if (!open) return null;
  return (
    <Modal open onClose={onCancel} title={title} size="sm">
      <p style={{ fontSize: 14, color: tk.textS, lineHeight: 1.6, marginBottom: 20 }}>{message}</p>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <Btn variant="secondary" onClick={onCancel}>Cancel</Btn>
        <Btn variant={danger ? "danger" : "primary"} onClick={onConfirm}>{confirmLabel}</Btn>
      </div>
    </Modal>
  );
}

function PendingActionsBanner({ tk, store, refresh, goTo, className = "" }) {
  const items = buildPendingActionItems(store);
  const [confirm, setConfirm] = useState(null);
  if (!items.length) return null;
  const resolveItem = (item) => {
    if (!item.resolve) return;
    updateStore((s) => { item.resolve(s); return s; });
    refresh();
    setConfirm(null);
  };
  return (
    <>
      <Card className={`pending-priority ${className}`.trim()} style={{ marginBottom: 20, borderColor: tk.red, background: tk.redBg }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
          <AlertCircle size={18} style={{ color: tk.red }} />
          <span style={{ fontWeight: 700, fontSize: 15, color: tk.text }}>Pending Actions</span>
          <span style={{ background: tk.red, color: "#fff", borderRadius: 12, fontSize: 11, fontWeight: 700, padding: "2px 8px" }}>{items.length}</span>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {items.map((item) => (
            <div key={item.id} style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", padding: "10px 12px", background: tk.card, borderRadius: 8, border: `1px solid ${tk.border}` }}>
              <button type="button" onClick={() => goTo(item)} style={{ flex: 1, textAlign: "left", background: "none", border: "none", cursor: "pointer", fontFamily: "'DM Sans'", fontSize: 13, color: tk.text, fontWeight: 500 }}>
                {item.msg}
              </button>
              {item.resolve && (
                <Btn variant="ghost" size="sm" onClick={() => setConfirm(item)} style={{ color: tk.textM }}>Dismiss</Btn>
              )}
            </div>
          ))}
        </div>
      </Card>
      {confirm && (
        <ConfirmModal
          open
          title="Dismiss pending item?"
          message={`Remove "${confirm.msg}" from pending list without opening the section?`}
          confirmLabel="Dismiss"
          danger
          onCancel={() => setConfirm(null)}
          onConfirm={() => resolveItem(confirm)}
        />
      )}
    </>
  );
}

