function Card({children,style,onClick,className}){
  const {tk}=useTheme();
  return <div onClick={onClick} className={className} style={{background:tk.card,border:`1px solid ${tk.border}`,borderRadius:12,padding:20,transition:"all 0.2s",cursor:onClick?"pointer":"default",...style}}>{children}</div>;
}
function Btn({children,variant="primary",size="md",onClick,disabled,style,full}){
  const {tk,dark}=useTheme();
  const sz={sm:{p:"5px 12px",fs:12},md:{p:"8px 16px",fs:13},lg:{p:"12px 28px",fs:15}};
  const vs={
    primary:{background:tk.gold,color:dark?"#000":"#fff"},
    secondary:{background:tk.sub,color:tk.text,border:`1px solid ${tk.border}`},
    danger:{background:tk.redBg,color:tk.red,border:`1px solid ${tk.red}`},
    success:{background:tk.greenBg,color:tk.green,border:`1px solid ${tk.green}`},
    ghost:{background:"transparent",color:tk.textS,padding:size==="sm"?"4px 8px":"6px 10px"},
    blue:{background:tk.blueBg,color:tk.blue,border:`1px solid ${tk.blue}`},
    orange:{background:tk.orangeBg,color:tk.orange,border:`1px solid ${tk.orange}`},
  };
  return <button onClick={onClick} disabled={disabled} style={{display:"inline-flex",alignItems:"center",justifyContent:"center",gap:6,fontFamily:"'DM Sans'",fontWeight:500,cursor:disabled?"not-allowed":"pointer",border:"none",borderRadius:8,transition:"all 0.15s",opacity:disabled?0.6:1,whiteSpace:"nowrap",width:full?"100%":undefined,fontSize:sz[size].fs,padding:sz[size].p,...vs[variant],...style}}>{children}</button>;
}
