                {myNotifs.length>0&&<span style={{position:"absolute",top:4,right:4,width:16,height:16,borderRadius:"50%",background:tk.red,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700}}>{myNotifs.length>9?"9+":myNotifs.length}</span>}
