function TourOverlay({steps,onDone,setPage}){
  const {tk}=useTheme();
  const [step,setStep]=useState(0);
  const cur=steps[step];
  useEffect(()=>{if(cur.page)setPage(cur.page);},[step]);
  const next=()=>{if(step<steps.length-1)setStep(s=>s+1);else onDone();};
  const prev=()=>{if(step>0)setStep(s=>s-1);};
  return(
    <div style={{position:"fixed",inset:0,zIndex:9000,pointerEvents:"none"}}>
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.55)",backdropFilter:"blur(2px)",pointerEvents:"all"}} onClick={onDone}/>
      <div style={{position:"fixed",bottom:32,right:32,width:340,background:tk.card,border:`2px solid ${tk.gold}`,borderRadius:16,padding:24,boxShadow:`0 20px 60px rgba(0,0,0,0.5), 0 0 0 1px ${tk.gold}44`,zIndex:9001,pointerEvents:"all",animation:"slideUp 0.3s ease"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
          <div style={{display:"flex",gap:4}}>{steps.map((_,i)=><div key={i} style={{width:i===step?20:6,height:6,borderRadius:3,background:i===step?tk.gold:tk.border,transition:"all 0.3s"}}/>)}</div>
          <button onClick={onDone} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,color:tk.textM,fontFamily:"'DM Sans'"}}>Skip</button>
        </div>
        <h3 style={{fontSize:17,fontWeight:700,color:tk.text,marginBottom:10}}>{cur.title}</h3>
        <p style={{fontSize:13,color:tk.textS,lineHeight:1.7,marginBottom:20}}>{cur.desc}</p>
        <div style={{display:"flex",gap:10,justifyContent:"space-between"}}>
          <Btn variant="secondary" size="sm" onClick={prev} disabled={step===0}><ChevronLeft size={13}/> Back</Btn>
          <Btn variant="primary" size="sm" onClick={next}>{step===steps.length-1?"Finish! 🎉":"Next >"}</Btn>
        </div>
        <div style={{textAlign:"center",fontSize:11,color:tk.textM,marginTop:12}}>{step+1} / {steps.length}</div>
      </div>
    </div>
  );
}

// ─── SALARY DETAIL POPUP ──────────────────────────────────────────────────────
function SalaryDetailPopup({user,onClose}){
  const {tk}=useTheme();
  const {store}=useSt();
  const isIntern=user.employmentType==="intern";
  const month=new Date().toISOString().slice(0,7);
  const calc=calcStaffSalary(store,user,month);
  const yearly=getYearlyAbsenceCount(store,user.id);
  const advDeduct=calc.advDeduct;
  const vis=user.panelVisibility||DEFAULT_PANEL_VISIBILITY;
  const simpleMode=!vis.lateDeduction;
  // Absent history
  const absHistory=store.attendance.filter(a=>a.userId===user.id&&a.awol).slice(0,5);
  const lateHistory=store.attendance.filter(a=>a.userId===user.id&&a.late).slice(0,5);
  // Leave balance
  const trackingPeriod=store.settings.leaveTrackingPeriod||"yearly";
  const periodKey=trackingPeriod==="monthly"?month:new Date().getFullYear().toString();
  return(
    <Modal open onClose={onClose} title={`Salary Detail — ${user.name}`} size="lg">
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:20,padding:"14px 18px",background:tk.sub,borderRadius:12}}>
        <Av initials={user.initials} size={52}/>
        <div style={{flex:1}}>
          <div style={{fontSize:17,fontWeight:700,color:tk.text}}>{user.name}</div>
          <div style={{fontSize:12,color:tk.textS,textTransform:"capitalize"}}>{user.role} · {user.employmentType} · Tenure: {calcTenure(user.joiningDate)}</div>
        </div>
        {isIntern
          ?<Badge color="orange">Intern — No Salary</Badge>
          :<div style={{textAlign:"right"}}>
            <div style={{fontSize:11,color:tk.textM,marginBottom:2}}>Est. This Month</div>
            <div style={{fontSize:28,fontWeight:700,color:tk.gold,fontFamily:"'Playfair Display'"}}>{fmtPKR(calc.net)}</div>
          </div>
        }
      </div>
      {isIntern
        ?<div style={{textAlign:"center",padding:24,color:tk.textM}}>Intern — Attendance report only, no salary calculation.</div>
        :<>
        {/* Components */}
        <div style={{marginBottom:18}}>
          <div style={{fontSize:11,fontWeight:600,color:tk.textS,letterSpacing:"0.06em",textTransform:"uppercase",marginBottom:10}}>Salary Components</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}} className="grid-4">
            {[["Basic",user.salary?.basic],["HRA",user.salary?.hra],["Transport",user.salary?.transport],["Medical",user.salary?.medical]].map(([k,v])=>(
              <div key={k} style={{background:tk.sub,borderRadius:10,padding:"10px 14px",textAlign:"center"}}>
                <div style={{fontSize:10,color:tk.textM,marginBottom:4}}>{k}</div>
                <div style={{fontSize:13,fontWeight:600,color:tk.text,fontFamily:"'JetBrains Mono',monospace"}}>{fmtPKR(v||0)}</div>
              </div>
            ))}
          </div>
          <div style={{marginTop:8,padding:"8px 14px",background:tk.goldBg,borderRadius:8,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontSize:13,color:tk.textS}}>Gross Monthly Salary</span>
            <span style={{fontSize:15,fontWeight:700,color:tk.gold,fontFamily:"'JetBrains Mono',monospace"}}>{fmtPKR(calc.gross)}</span>
          </div>
        </div>
        {/* Monthly calc */}
        <div style={{marginBottom:18}}>
          <div style={{fontSize:11,fontWeight:600,color:tk.textS,letterSpacing:"0.06em",textTransform:"uppercase",marginBottom:10}}>
            This Month ({new Date().toLocaleDateString("en-PK",{month:"long",year:"numeric"})})
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:3}}>
            {(simpleMode?[
              {label:"Daily rate",val:fmtPKR(Math.round(calc.perDay)),c:tk.text},
              {label:"Present days",val:`${calc.present}`,c:tk.green},
              {label:"Absent deduction",val:calc.awol?`-${fmtPKR(Math.round(calc.awol*calc.perDay))}`:"None",c:calc.awol?tk.red:tk.textM},
              {label:"Overtime",val:`+${fmtPKR(Math.round(calc.otPay))}`,c:tk.green},
              {label:"Advance",val:advDeduct?`-${fmtPKR(advDeduct)}`:"None",c:advDeduct?tk.red:tk.textM},
            ]:[
              {label:"Working Days (standard)",val:`${calc.workDays} days`,c:tk.text},
              {label:"Present Days",val:`${calc.present} days`,c:tk.green},
              {label:"Approved Leaves (no cut)",val:`${calc.leaveDays} days`,c:tk.blue},
              {label:"Half Days",val:`${calc.half}`,c:tk.orange},
              {label:"AWOL Days",val:`${calc.awol} days`,c:tk.red},
              {label:"Late Arrivals",val:`${calc.lateMin} min (−${fmtPKR(Math.round(calc.lateDeduct))})`,c:tk.orange},
              {label:"Overtime",val:`${calc.ot} min (+${fmtPKR(Math.round(calc.otPay))})`,c:tk.green},
              {label:"Advance Deduction",val:advDeduct?`−${fmtPKR(advDeduct)}`:"None",c:advDeduct?tk.red:tk.textM},
            ]).map(row=>(
              <div key={row.label} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 12px",background:tk.sub,borderRadius:8}}>
                <span style={{fontSize:13,color:tk.textS}}>{row.label}</span>
                <span style={{fontSize:13,fontWeight:600,color:row.c,fontFamily:"'JetBrains Mono',monospace"}}>{row.val}</span>
              </div>
            ))}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 14px",background:tk.goldBg,border:`2px solid ${tk.gold}`,borderRadius:10,marginTop:4}}>
              <span style={{fontSize:14,fontWeight:600,color:tk.text}}>🎯 Estimated Net Salary</span>
              <span style={{fontSize:20,fontWeight:700,color:tk.gold,fontFamily:"'Playfair Display'"}}>{fmtPKR(calc.net)}</span>
            </div>
          </div>
        </div>
        <div style={{marginBottom:14,padding:"10px 12px",background:tk.sub,borderRadius:8,fontSize:12,color:tk.textS}}>
          Yearly absences: <strong style={{color:tk.red}}>{yearly.total}</strong> · Approved leave days: {yearly.approvedLeaveDays}
        </div>
        {/* Leave balance */}
        <div style={{marginBottom:18}}>
          <div style={{fontSize:11,fontWeight:600,color:tk.textS,letterSpacing:"0.06em",textTransform:"uppercase",marginBottom:10}}>
            Leave Balance ({trackingPeriod==="monthly"?"This Month":"This Year"})
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(120px,1fr))",gap:8}}>
            {store.leaveTypes.map(lt=>{
              const used=store.leaves.filter(l=>l.userId===user.id&&l.leaveTypeId===lt.id&&l.status==="approved"&&l.dates.some(d=>d.startsWith(periodKey))).reduce((s,l)=>s+(l.dates||[]).length,0);
              const rem=Math.max(0,lt.limit-used);
              return(
                <div key={lt.id} style={{background:tk.sub,borderRadius:10,padding:"10px 12px",textAlign:"center"}}>
                  <div style={{width:8,height:8,borderRadius:"50%",background:lt.color,margin:"0 auto 4px"}}/>
                  <div style={{fontSize:10,color:tk.textM,marginBottom:4}}>{lt.name}</div>
                  <div style={{fontSize:18,fontWeight:700,color:rem===0?tk.red:tk.text}}>{rem}</div>
                  <div style={{fontSize:10,color:tk.textM}}>of {lt.limit} left</div>
                  <div style={{height:4,background:tk.border,borderRadius:2,marginTop:5}}>
                    <div style={{height:"100%",width:`${Math.min((used/lt.limit)*100,100)}%`,background:lt.color,borderRadius:2}}/>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
        {/* History */}
        {(absHistory.length>0||lateHistory.length>0)&&(
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}} className="grid-2">
            {absHistory.length>0&&(
              <div>
                <div style={{fontSize:11,fontWeight:600,color:tk.red,marginBottom:8,textTransform:"uppercase",letterSpacing:"0.04em"}}>Recent AWOL</div>
                {absHistory.map(a=><div key={a.id} style={{fontSize:12,color:tk.textS,padding:"4px 0",borderBottom:`1px solid ${tk.border}`}}>{fmtDate(a.date)}</div>)}
              </div>
            )}
            {lateHistory.length>0&&(
              <div>
                <div style={{fontSize:11,fontWeight:600,color:tk.orange,marginBottom:8,textTransform:"uppercase",letterSpacing:"0.04em"}}>Recent Late</div>
                {lateHistory.map(a=><div key={a.id} style={{display:"flex",justifyContent:"space-between",fontSize:12,color:tk.textS,padding:"4px 0",borderBottom:`1px solid ${tk.border}`}}><span>{fmtDate(a.date)}</span><span style={{color:tk.orange}}>Late</span></div>)}
              </div>
            )}
          </div>
        )}
        </>
      }
      <div style={{marginTop:24,display:"flex",gap:10,justifyContent:"flex-end",flexWrap:"wrap"}}>
        <Btn variant="blue" size="sm"><Download size={13}/> PDF Report</Btn>
        <Btn variant="success" size="sm"><Download size={13}/> Excel Report</Btn>
        <Btn variant="secondary" onClick={onClose}>Close</Btn>
      </div>
    </Modal>
  );
}



// ─── BIRTHDAY POPUP ────────────────────────────────────────────────────────
