// ─── STAFF LAYOUT ─────────────────────────────────────────────────────────────
const SNAV=[{id:"dashboard",label:"Home",icon:LayoutDashboard},{id:"calendar",label:"Calendar",icon:Calendar},{id:"requests",label:"Requests",icon:FileText}];
function StaffLayout({page,setPage,requestsTab,showTour,setShowTour}){
  const{user,logout}=useAuth();const{tk,dark,toggleTheme}=useTheme();const{store,refresh}=useSt();
  const[notifOpen,setNotifOpen]=useState(false),[annPopup,setAnnPopup]=useState(null),[bdayPopup,setBdayPopup]=useState(false);
  const myNotifs=(store.notifications||[]).filter(n=>n.userId===user.id&&!n.read);
  const markRead=()=>{updateStore(s=>{s.notifications=s.notifications.map(n=>n.userId===user.id?{...n,read:true}:n);return s;});refresh();};
  useEffect(()=>{const anns=store.announcements.filter(a=>{const t=a.targetType==="all"||(user.deptIds||[]).some(d=>(a.targetDeptIds||[]).includes(d));return t&&!(a.seenBy||[]).includes(user.id);});if(anns.length>0)setAnnPopup(anns[anns.length-1]);},[]);
  useEffect(()=>{const todMD=todayStr().slice(5);if(user.dob&&user.dob.slice(5)===todMD)setBdayPopup(true);},[]);
  const markAnnSeen=(ann)=>{updateStore(s=>{s.announcements=s.announcements.map(a=>a.id===ann.id?{...a,seenBy:[...(a.seenBy||[]),user.id]}:a);return s;});setAnnPopup(null);refresh();};
  const STAFF_TOUR=[{title:"👋 Alvin Desk!",desc:"Your personal HR portal. Quick tour!",page:"dashboard"},{title:"⏰ IN / OUT",desc:"Big buttons mark attendance. Live clock shows current time.",page:"dashboard"},{title:"📅 My Calendar",desc:"View leaves, off days, attendance with IN/OUT times per day.",page:"calendar"},{title:"📝 Requests",desc:"Submit leave, correction, or advance salary. Track status.",page:"requests"}];
  return(
    <div className="wm-bg" style={{display:"flex",minHeight:"100vh",background:tk.bg}}>
      {showTour&&<TourOverlay steps={STAFF_TOUR} onDone={()=>{setShowTour(false);updateStore(s=>{s.users=s.users.map(u=>u.id===user.id?{...u,tourDone:true}:u);return s;});refresh();}} setPage={setPage}/>}
      {annPopup&&<AnnouncePopup ann={annPopup} onClose={()=>markAnnSeen(annPopup)}/>}
      {bdayPopup&&<BirthdayPopup name={user.name} onClose={()=>setBdayPopup(false)}/>}
      <aside className="sb" style={{width:200,minHeight:"100vh",background:tk.card,borderRight:`1px solid ${tk.border}`,display:"flex",flexDirection:"column",position:"fixed",top:0,left:0,bottom:0,zIndex:100}}>
        <div style={{padding:"16px 14px",borderBottom:`1px solid ${tk.border}`,display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:30,height:30,borderRadius:7,background:`linear-gradient(135deg,${tk.gold},#b45309)`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Building2 size={16} color="#fff"/></div>
          <div style={{fontFamily:"'Playfair Display'",fontWeight:700,fontSize:14,color:tk.text}}>Alvin Desk</div>
        </div>
        <nav style={{flex:1,padding:"10px 8px"}}>
          {SNAV.map(item=>{const active=page===item.id;return(<button key={item.id} onClick={()=>setPage(item.id)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderRadius:8,width:"100%",border:"none",cursor:"pointer",fontFamily:"'DM Sans'",fontSize:13.5,fontWeight:active?500:400,color:active?tk.gold:tk.textS,background:active?tk.goldBg:"transparent",transition:"all 0.15s",marginBottom:2}}><item.icon size={17}/>{item.label}</button>);})}
          <button onClick={()=>setShowTour(true)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderRadius:8,width:"100%",border:"none",cursor:"pointer",fontFamily:"'DM Sans'",fontSize:13.5,color:tk.gold,background:tk.goldBg,marginTop:8}}><Star size={17}/>Help</button>
        </nav>
        <div style={{padding:"8px 8px",borderTop:`1px solid ${tk.border}`}}>
          <button onClick={logout} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderRadius:8,width:"100%",border:"none",cursor:"pointer",fontFamily:"'DM Sans'",fontSize:13.5,color:tk.red,background:"transparent"}}><LogOut size={17}/> Logout</button>
        </div>
      </aside>
      <div className="main-ml" style={{flex:1,marginLeft:200,display:"flex",flexDirection:"column"}}>
        <header className="tpad" style={{height:58,background:tk.card,borderBottom:`1px solid ${tk.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 22px",position:"sticky",top:0,zIndex:50}}>
          <div/>
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            <button onClick={toggleTheme} style={{background:"none",border:"none",cursor:"pointer",padding:8,borderRadius:8,display:"flex",color:tk.textS}}>{dark?<Sun size={17} style={{color:tk.gold}}/>:<Moon size={17}/>}</button>
            <div style={{position:"relative"}}>
              <button onClick={()=>setNotifOpen(!notifOpen)} style={{background:"none",border:"none",cursor:"pointer",padding:8,borderRadius:8,position:"relative",display:"flex",color:tk.textS}}>
                <Bell size={17}/>
                {myNotifs.length>0&&<span style={{position:"absolute",top:4,right:4,width:14,height:14,borderRadius:"50%",background:tk.red,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700}}>{myNotifs.length}</span>}
              </button>
              {notifOpen&&(<><div onClick={()=>setNotifOpen(false)} style={{position:"fixed",inset:0,zIndex:200}}/>
              <div style={{position:"absolute",top:42,right:0,width:300,zIndex:300,background:tk.card,border:`1px solid ${tk.border}`,borderRadius:12,boxShadow:tk.shadowLg,overflow:"hidden"}}>
                <div style={{padding:"12px 16px",borderBottom:`1px solid ${tk.border}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontWeight:600,fontSize:14,color:tk.text}}>Notifications</span>{myNotifs.length>0&&<button onClick={markRead} style={{fontSize:12,color:tk.gold,background:"none",border:"none",cursor:"pointer"}}>Mark read</button>}</div>
                <div style={{maxHeight:280,overflowY:"auto"}}>{myNotifs.length===0?<div style={{padding:24,textAlign:"center",fontSize:13,color:tk.textM}}>All caught up ✓</div>:myNotifs.map(n=><div key={n.id} style={{padding:"10px 14px",borderBottom:`1px solid ${tk.border}`,background:tk.goldBg}}><p style={{fontSize:13,color:tk.text,marginBottom:2}}>{n.msg}</p><p style={{fontSize:11,color:tk.textM}}>{n.date}</p></div>)}</div>
              </div></>)}
            </div>
            <div style={{display:"flex",alignItems:"center",gap:8,paddingLeft:10,borderLeft:`1px solid ${tk.border}`}}>
              <Av initials={user.initials}/>
              <div><div style={{fontSize:13,fontWeight:500,color:tk.text,lineHeight:1.2}}>{user.name}</div><div style={{fontSize:11,color:tk.textM,textTransform:"capitalize"}}>{user.employmentType}</div></div>
            </div>
          </div>
        </header>
        <main className="tpad" style={{flex:1,padding:24,animation:"fadeIn 0.3s ease"}}><StaffRouter page={page} setPage={setPage} requestsTab={requestsTab}/></main>
      </div>
      <nav className="mobile-nav">
        {SNAV.map(item=><button key={item.id} onClick={()=>setPage(item.id)} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2,padding:"8px 10px",border:"none",background:"none",cursor:"pointer",color:page===item.id?tk.gold:tk.textS,fontFamily:"'DM Sans'",fontSize:9}}><item.icon size={20}/>{item.label}</button>)}
        <button onClick={logout} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2,padding:"8px 10px",border:"none",background:"none",cursor:"pointer",color:tk.red,fontFamily:"'DM Sans'",fontSize:9}}><LogOut size={20}/>Out</button>
      </nav>
    </div>
  );
}
function StaffRouter({page,setPage,requestsTab}){switch(page){case"dashboard":return<StaffDash setPage={setPage}/>;case"calendar":return<StaffCal/>;case"requests":return<StaffReqs initialTab={requestsTab}/>;default:return<StaffDash setPage={setPage}/>;}}

// ─── STAFF DASHBOARD ──────────────────────────────────────────────────────────
function StaffDash({setPage}){
  const{user}=useAuth();const{tk}=useTheme();const{store,refresh}=useSt();
  const{push}=useToast();
  const[punching,setPunching]=useState(false);
  const[time,setTime]=useState(new Date());
  useEffect(()=>{const t=setInterval(()=>setTime(new Date()),1000);return()=>clearInterval(t);},[]);
  const today=todayStr();
  const todayAtt=store.attendance.find(a=>a.userId===user.id&&a.date===today);
  const isOff=(store.offDays||[]).some(o=>o.date===today&&(o.scope==="all"||(o.userIds||[]).includes(user.id)));
  const onLeave=store.leaves.some(l=>l.userId===user.id&&l.status==="approved"&&leaveDatesOf(l).includes(today));
  const vis={...DEFAULT_PANEL_VISIBILITY,...user.panelVisibility};
  const isIntern=user.employmentType==="intern";
  const shift=store.shifts.find(s=>s.id===user.shiftId)||(user.shiftOverride?{name:"Custom",...user.shiftOverride}:null);
  const gross=calcTotal(user.salary);
  const myLeaves=store.leaves.filter(l=>l.userId===user.id&&l.status==="approved").reduce((s,l)=>s+(l.dates||[]).length,0);
  const month=new Date().toISOString().slice(0,7);
  const sal=calcStaffSalary(store,user,month);
  const {present,leaveDays,ot,otPay,lateDeduct,advDeduct,net,awol}=sal;
  const wDays=sal.workDays;
  const advancedMode=!!vis.lateDeduction;
  const doPunch=async(type)=>{
    if(punching)return;
    if(type==="in"&&todayAtt?.inTime)return;
    if(type==="out"&&(!todayAtt?.inTime||todayAtt?.outTime))return;
    setPunching(true);
    let geo=null;
    const locOn=!!store.settings?.locationRestriction&&!user.locationExempt;
    if(locOn){
      try{
        const pos=await getCurrentPosition();
        const gf=validateGeofence(store,user,pos.lat,pos.lng,pos.accuracy);
        geo={lat:pos.lat,lng:pos.lng,accuracy:pos.accuracy,distance:gf.distance,office:gf.office,within:gf.within};
        if(!gf.ok){
          push(gf.warning||"Outside allowed work area","error");
          if(gf.mode!=="warn_outside"&&store.settings?.locationMode!=="warn"){setPunching(false);return;}
        }else if(gf.warning) push(gf.warning,"warning");
      }catch(e){
        push(`Location required: ${e.message||"enable GPS"}`, "error");
        if(store.settings?.weakGpsMode==="block"){setPunching(false);return;}
      }
    }
    let ok=false;
    updateStore(s=>{
      const r=markAttendancePunch(s,{user,type,geo,actor:user});
      if(!r.ok){push(r.error,"error");return s;}
      ok=true;
      return s;
    });
    if(ok){refresh();push(type==="in"?"Checked in successfully":"Checked out successfully","success");}
    setPunching(false);
  };
  const handleIn=()=>doPunch("in");
  const handleOut=()=>doPunch("out");
  const lastPunch=(store.locationPunches||[]).filter(p=>p.userId===user.id&&p.date===today).slice(-1)[0];
  const threeMonthsAgo=new Date(Date.now()-90*86400000).toISOString().split("T")[0];
  const myAtt=store.attendance.filter(a=>a.userId===user.id&&a.date>=threeMonthsAgo).slice(-7).reverse();
  return(
    <div className="fade-in">
      <Card style={{marginBottom:20,textAlign:"center",padding:"32px 20px"}}>
        <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:"clamp(32px,7vw,52px)",fontWeight:500,color:tk.gold,letterSpacing:2,lineHeight:1,marginBottom:6}}>{time.toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:true})}</div>
        <div style={{fontSize:14,color:tk.textS,marginBottom:8}}>{time.toLocaleDateString("en-PK",{weekday:"long",day:"numeric",month:"long",year:"numeric"})}</div>
        {store.settings?.locationRestriction&&!user.locationExempt&&(
          <div style={{fontSize:11,color:tk.textM,marginBottom:14,display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
            <MapPin size={12} style={{color:tk.gold}}/>
            Geo-fence active · {store.settings.locationMode==="warn"?"warn outside":"block outside"}
            {lastPunch&&<span style={{color:lastPunch.withinFence?tk.green:tk.orange}}>· {lastPunch.withinFence?"On-site":"Off-site"}</span>}
          </div>
        )}
        {punching&&<div style={{fontSize:12,color:tk.textM,marginBottom:12}}>Verifying location…</div>}
        {isOff||onLeave
          ?<div style={{padding:"14px 28px",borderRadius:12,background:tk.blueBg,border:`1px solid ${tk.blue}`,display:"inline-block",color:tk.blue,fontWeight:500}}>{isOff?"🏖️ Today is an Off Day":"🌿 You are on Approved Leave"}</div>
          :<div style={{display:"flex",gap:12,justifyContent:"center",maxWidth:440,margin:"0 auto"}}>
            <button onClick={handleIn} disabled={!!todayAtt?.inTime||punching} style={{flex:1,padding:"18px 20px",borderRadius:14,border:"none",cursor:todayAtt?.inTime?"default":"pointer",background:todayAtt?.inTime?tk.sub:`linear-gradient(135deg,#15803d,#16a34a)`,color:todayAtt?.inTime?tk.textM:"#fff",fontSize:17,fontWeight:600,fontFamily:"'DM Sans'",boxShadow:todayAtt?.inTime?"none":"0 6px 24px rgba(21,128,61,0.35)",transition:"all 0.2s",opacity:todayAtt?.inTime?0.7:1}}>{todayAtt?.inTime?`✓ IN · ${fmt12(todayAtt.inTime)}`:"Mark IN"}</button>
            <button onClick={handleOut} disabled={!todayAtt?.inTime||!!todayAtt?.outTime||punching} style={{flex:1,padding:"18px 20px",borderRadius:14,border:"none",cursor:(!todayAtt?.inTime||todayAtt?.outTime)?"default":"pointer",background:todayAtt?.outTime?tk.sub:!todayAtt?.inTime?tk.sub:`linear-gradient(135deg,#b45309,#d97706)`,color:(!todayAtt?.inTime||todayAtt?.outTime)?tk.textM:"#fff",fontSize:17,fontWeight:600,fontFamily:"'DM Sans'",boxShadow:(!todayAtt?.inTime||todayAtt?.outTime)?"none":"0 6px 24px rgba(180,83,9,0.35)",transition:"all 0.2s",opacity:(!todayAtt?.inTime||todayAtt?.outTime)?0.7:1}}>{todayAtt?.outTime?`✓ OUT · ${fmt12(todayAtt.outTime)}`:"Mark OUT"}</button>
          </div>
        }
      </Card>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(140px,1fr))",gap:10,marginBottom:16}} className="grid-4">
        <Card style={{textAlign:"center",padding:14}}><div style={{fontSize:10,color:tk.textM,textTransform:"uppercase",marginBottom:5}}>Shift</div><div style={{fontSize:13,fontWeight:600,color:tk.text}}>{user.shiftOverride?"⚡ Override":shift?.name||"—"}</div><div style={{fontSize:11,color:tk.textS}}>{user.shiftOverride?`${fmt12(user.shiftOverride.start)}–${fmt12(user.shiftOverride.end)}`:`${fmt12(shift?.start)}–${fmt12(shift?.end)}`}</div></Card>
        {vis.leaveBalance&&<Card style={{textAlign:"center",padding:14,cursor:"pointer"}} onClick={()=>setPage("requests")}><div style={{fontSize:10,color:tk.textM,textTransform:"uppercase",marginBottom:5}}>Leaves Used</div><div style={{fontSize:24,fontWeight:700,fontFamily:"'Playfair Display'",color:tk.text}}>{myLeaves}</div><div style={{fontSize:11,color:tk.textS}}>this year</div></Card>}
        {vis.salary&&!isIntern&&<Card style={{textAlign:"center",padding:14}}><div style={{fontSize:10,color:tk.textM,textTransform:"uppercase",marginBottom:5}}>Gross</div><div style={{fontSize:16,fontWeight:700,color:tk.gold}}>{fmtPKR(gross)}</div></Card>}
        <Card style={{textAlign:"center",padding:14}}><div style={{fontSize:10,color:tk.textM,textTransform:"uppercase",marginBottom:5}}>Tenure</div><div style={{fontSize:20,fontWeight:700,fontFamily:"'Playfair Display'",color:tk.text}}>{calcTenure(user.joiningDate)}</div></Card>
      </div>
      {vis.salaryCalc&&!isIntern&&<Card style={{marginBottom:16}}>
        <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:12}}>💰 Salary Estimate — {new Date().toLocaleDateString("en-PK",{month:"long",year:"numeric"})}</div>
        {(advancedMode?(
          [{l:"Present Days",v:`${present}/${wDays}`,c:tk.blue},...(vis.leaveBalance?[{l:"Leave Days (no cut)",v:`${leaveDays}d`,c:tk.blue}]:[]),...(vis.overtime?[{l:"Overtime",v:`${ot}m (+${fmtPKR(Math.round(otPay))})`,c:tk.green}]:[]),{l:"Late Deduction",v:`-${fmtPKR(Math.round(lateDeduct))}`,c:tk.orange},{l:"Absent Days",v:`${awol}d`,c:tk.red},{l:"Advance Deduction",v:advDeduct?`-${fmtPKR(advDeduct)}`:"None",c:tk.textM},{l:"Estimated Net",v:fmtPKR(net),c:tk.gold}]
        ):(
          [{l:"Daily Rate",v:fmtPKR(Math.round(sal.perDay)),c:tk.textS},{l:"Present Days",v:`${present}/${wDays}`,c:tk.blue},...(vis.leaveBalance?[{l:"Leave Days",v:`${leaveDays}d`,c:tk.blue}]:[]),{l:"Absent Deduction",v:awol?`-${fmtPKR(Math.round(awol*sal.perDay))}`:"None",c:tk.red},{l:"Advance Deduction",v:advDeduct?`-${fmtPKR(advDeduct)}`:"None",c:tk.textM},{l:"Estimated Net",v:fmtPKR(net),c:tk.gold}]
        )).map(row=>(
          <div key={row.l} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${tk.border}`}}>
            <span style={{fontSize:13,color:tk.textS}}>{row.l}</span>
            <span style={{fontSize:13,fontWeight:600,color:row.c,fontFamily:"'JetBrains Mono',monospace"}}>{row.v}</span>
          </div>
        ))}
      </Card>}
      <Card>
        <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:14}}>Recent Attendance <span style={{fontSize:11,color:tk.textM,fontWeight:400}}>(last 3 months)</span></div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
            <thead><tr style={{borderBottom:`1px solid ${tk.border}`}}>{["Date","IN","OUT","Status"].map(h=><th key={h} style={{padding:"8px 12px",textAlign:"left",fontSize:11,fontWeight:600,color:tk.textM,textTransform:"uppercase"}}>{h}</th>)}</tr></thead>
            <tbody>
              {myAtt.length===0?<tr><td colSpan={4}><Empty icon={Clock} title="No recent attendance"/></td></tr>:myAtt.map(a=>(
                <tr key={a.id} style={{borderBottom:`1px solid ${tk.border}`}}>
                  <td style={{padding:"9px 12px",color:tk.textS}}>{fmtDate(a.date)}</td>
                  <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",fontSize:12,color:tk.text}}>{fmt12(a.inTime)}</td>
                  <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",fontSize:12,color:tk.text}}>{fmt12(a.outTime)}</td>
                  <td style={{padding:"9px 12px"}}><Badge color={a.awol?"red":a.halfDay?"orange":a.late?"orange":"green"}>{a.awol?"AWOL":a.halfDay?"Half Day":a.late?"Late":"Present"}</Badge></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{marginTop:10,textAlign:"right"}}>
          <button onClick={()=>setPage("requests","history")} style={{fontSize:12,color:tk.gold,background:"none",border:"none",cursor:"pointer",textDecoration:"underline"}}>Need records older than 3 months? Request from admin →</button>
        </div>
      </Card>
    </div>
  );
}

// ─── STAFF CALENDAR ───────────────────────────────────────────────────────────
function StaffCal(){
  const{user}=useAuth();const{tk}=useTheme();const{store}=useSt();
  const[cur,setCur]=useState(new Date());
  const year=cur.getFullYear(),month=cur.getMonth();
  const firstDay=new Date(year,month,1).getDay();
  const daysInMonth=new Date(year,month+1,0).getDate();
  const monthStr=`${year}-${String(month+1).padStart(2,"0")}`;
  const offDates=new Set((store.offDays||[]).filter(o=>o.scope==="all"||(o.userIds||[]).includes(user.id)).map(o=>o.date));
  const leaveDates=new Set((store.leaves||[]).filter(l=>l.userId===user.id&&l.status==="approved").flatMap(l=>leaveDatesOf(l)));
  const pkHMap={};PK_HOLIDAYS.forEach(h=>{pkHMap[h.date]=h.name;});
  const today=todayStr();
  const days=[];for(let i=0;i<firstDay;i++)days.push(null);for(let i=1;i<=daysInMonth;i++)days.push(i);
  const attMap={};store.attendance.filter(a=>a.userId===user.id).forEach(a=>{attMap[a.date]=a;});
  return(
    <div className="fade-in">
      <div style={{marginBottom:24}}><h1 style={{fontSize:26,color:tk.text,marginBottom:4}}>My Calendar</h1><p style={{fontSize:13,color:tk.textS}}>Attendance, leaves and off days</p></div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12,flexWrap:"wrap",gap:10}}>
        <Btn variant="secondary" size="sm" onClick={()=>setCur(new Date(year,month-1,1))}><ChevronLeft size={15}/></Btn>
        <span style={{fontFamily:"'Playfair Display'",fontSize:18,fontWeight:600,color:tk.text}}>{cur.toLocaleDateString("en-PK",{month:"long",year:"numeric"})}</span>
        <Btn variant="secondary" size="sm" onClick={()=>setCur(new Date(year,month+1,1))}><ChevronRight size={15}/></Btn>
      </div>
      <div style={{display:"flex",gap:10,marginBottom:12,flexWrap:"wrap"}}>{[["Off/Holiday",tk.orange],["My Leave",tk.blue],["Present",tk.green],["No Record",tk.red],["Today",tk.gold]].map(([l,c])=><div key={l} style={{display:"flex",alignItems:"center",gap:4,fontSize:11,color:tk.textS}}><div style={{width:9,height:9,borderRadius:2,background:c}}/>{l}</div>)}</div>
      <Card style={{padding:10}}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2,marginBottom:4}}>{["Su","Mo","Tu","We","Th","Fr","Sa"].map(d=><div key={d} style={{textAlign:"center",fontSize:10,fontWeight:600,color:tk.textM,padding:"4px 0",textTransform:"uppercase"}}>{d}</div>)}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2}}>
          {days.map((day,idx)=>{
            if(!day)return<div key={idx}/>;
            const dateStr=`${monthStr}-${String(day).padStart(2,"0")}`;
            const isOff=offDates.has(dateStr)||!!pkHMap[dateStr],isLeave=leaveDates.has(dateStr),isToday=dateStr===today;
            const att=attMap[dateStr],isPresent=!!att&&!att.awol,isNoRecord=!att&&!isOff&&!isLeave&&dateStr<today;
            const bgColor=isToday?tk.goldBg:isLeave?tk.blueBg:isOff?tk.orangeBg:isPresent?tk.greenBg:isNoRecord?tk.redBg:"transparent";
            const borderClr=isToday?tk.gold:isLeave?tk.blue:isOff?tk.orange:isPresent?tk.green:isNoRecord?tk.red:tk.border;
            return(
              <div key={dateStr} style={{minHeight:68,padding:"4px 5px",borderRadius:5,background:bgColor,border:`1px solid ${borderClr}`}}>
                <div style={{fontSize:11,fontWeight:isToday?700:400,color:isToday?tk.gold:tk.text}}>{day}</div>
                {isOff&&<div style={{fontSize:8,color:tk.orange,lineHeight:1.2,marginTop:1}}>{pkHMap[dateStr]?.slice(0,10)||"Off"}</div>}
                {isLeave&&!isOff&&<div style={{fontSize:8,color:tk.blue,marginTop:1}}>Leave</div>}
                {att&&<div style={{marginTop:2}}>
                  <div style={{fontSize:8,color:tk.green,fontFamily:"'JetBrains Mono',monospace"}}>{fmt12(att.inTime)}</div>
                  {att.outTime&&<div style={{fontSize:8,color:tk.orange,fontFamily:"'JetBrains Mono',monospace"}}>{fmt12(att.outTime)}</div>}
                  {att.late&&<div style={{fontSize:7,color:tk.orange}}>Late</div>}
                  {att.halfDay&&<div style={{fontSize:7,color:tk.orange}}>½</div>}
                  {att.awol&&<div style={{fontSize:7,color:tk.red}}>AWOL</div>}
                </div>}
                {isNoRecord&&<div style={{fontSize:8,color:tk.red,marginTop:1}}>No Record</div>}
              </div>
            );
          })}
        </div>
      </Card>
    </div>
  );
}

// ─── STAFF REQUESTS ───────────────────────────────────────────────────────────
function StaffReqs({initialTab="leave"}){
  const{user}=useAuth();const{tk}=useTheme();const{store,refresh}=useSt();
  const[tab,setTab]=useState(initialTab);
  useEffect(()=>{setTab(initialTab);},[initialTab]);
  const[lMode,setLMode]=useState("range"),[lFrom,setLFrom]=useState(todayStr()),[lTo,setLTo]=useState(todayStr()),[lMulti,setLMulti]=useState([todayStr()]),[lLtId,setLLtId]=useState(store.leaveTypes[0]?.id||""),[lReason,setLReason]=useState("");
  const[corrF,setCorrF]=useState({date:todayStr(),inTime:"",outTime:"",reason:""});
  const[advF,setAdvF]=useState({amount:"",monthly:"",reason:"",type:"installment"});
  const[histReq,setHistReq]=useState({from:"",reason:""});
  const getLDates=()=>lMode==="range"?getDatesInRange(lFrom,lTo):lMode==="multi"?lMulti.filter(Boolean):[lFrom];
  const subLeave=()=>{if(!lReason)return;const dates=getLDates();updateStore(s=>{s.leaves.push({id:uid(),userId:user.id,leaveTypeId:lLtId,dateFrom:dates[0],dateTo:dates[dates.length-1],dates,reason:lReason,status:"pending",appliedOn:todayStr(),approvedBy:null});notifyAdmins(s,{type:"leave",msg:`${user.name} submitted a leave request`});return s;});refresh();setLReason("");};
  const subCorr=()=>{if(!corrF.reason)return;updateStore(s=>{s.corrections.push({id:uid(),userId:user.id,...corrF,reqIn:corrF.inTime,reqOut:corrF.outTime,status:"pending",appliedOn:todayStr()});notifyAdmins(s,{type:"correction",msg:`${user.name} submitted attendance correction`});return s;});refresh();setCorrF({date:todayStr(),inTime:"",outTime:"",reason:""});};
  const subAdv=()=>{if(!advF.amount||!advF.reason)return;const gross=calcTotal(user.salary);updateStore(s=>{submitAdvanceRequest(s,{user,amount:advF.amount,monthly:advF.monthly,reason:advF.reason,type:advF.type,calcTotal});processPayrollAdvanceDeductions(s);return s;});refresh();setAdvF({amount:"",monthly:"",reason:"",type:"installment"});};
  const subHist=()=>{if(!histReq.from||!histReq.reason)return;updateStore(s=>{if(!s.historyRequests)s.historyRequests=[];s.historyRequests.push({id:uid(),userId:user.id,dateFrom:histReq.from,reason:histReq.reason,status:"pending",appliedOn:todayStr()});notifyAdmins(s,{type:"history",msg:`${user.name} requested old records from ${histReq.from}`});return s;});refresh();setHistReq({from:"",reason:""});};
  const myLeaves=store.leaves.filter(l=>l.userId===user.id);
  const myCorr=store.corrections.filter(c=>c.userId===user.id);
  const myAdv=getActiveAdvanceRequests(store).filter(a=>a.userId===user.id);
  const myHist=(store.historyRequests||[]).filter(h=>h.userId===user.id);
  const allowInstallments=store.settings.allowAdvanceInstallments!==false;
  return(
    <div className="fade-in">
      <div style={{marginBottom:24}}><h1 style={{fontSize:26,color:tk.text,marginBottom:4}}>Requests</h1><p style={{fontSize:13,color:tk.textS}}>Submit and track your requests</p></div>
      <div style={{display:"flex",gap:4,marginBottom:20,borderBottom:`1px solid ${tk.border}`,overflowX:"auto"}}>
        {[["leave","Leave"],["correction","Correction"],["advance","Advance"],["history","Old Records"]].map(([id,l])=>(
          <button key={id} onClick={()=>setTab(id)} style={{padding:"8px 14px",border:"none",background:"none",cursor:"pointer",fontFamily:"'DM Sans'",fontSize:13,fontWeight:tab===id?600:400,color:tab===id?tk.gold:tk.textS,borderBottom:tab===id?`2px solid ${tk.gold}`:"2px solid transparent",marginBottom:-1,whiteSpace:"nowrap"}}>{l}</button>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"360px 1fr",gap:20}} className="grid2">
        <Card>
          {tab==="leave"&&(<>
            <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:14}}>Leave Request</div>
            <Inp label="Leave Type" value={lLtId} onChange={setLLtId} type="select" options={store.leaveTypes.map(l=>({value:l.id,label:l.name}))}/>
            <div style={{marginBottom:12}}>
              <div style={{fontSize:12,fontWeight:500,color:tk.textS,marginBottom:8}}>Date Mode</div>
              <div style={{display:"flex",gap:6,marginBottom:10}}>{[["range","Range"],["single","Single"],["multi","Multiple"]].map(([v,l])=><button key={v} onClick={()=>setLMode(v)} style={{padding:"5px 10px",borderRadius:20,border:`1.5px solid ${lMode===v?tk.gold:tk.border}`,background:lMode===v?tk.goldBg:"transparent",color:lMode===v?tk.gold:tk.textS,fontSize:11,cursor:"pointer",fontFamily:"'DM Sans'"}}>{l}</button>)}</div>
              {lMode==="range"&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 10px"}}><Inp label="From" value={lFrom} onChange={setLFrom} type="date"/><Inp label="To" value={lTo} onChange={setLTo} type="date"/></div>}
              {lMode==="single"&&<Inp label="Date" value={lFrom} onChange={setLFrom} type="date"/>}
              {lMode==="multi"&&<div>{lMulti.map((d,i)=><div key={i} style={{display:"flex",gap:6,marginBottom:6}}><input type="date" value={d} onChange={e=>setLMulti(x=>x.map((y,j)=>j===i?e.target.value:y))} style={{flex:1,padding:"6px 10px",borderRadius:8,border:`1px solid ${tk.border}`,background:tk.card,color:tk.text,fontSize:12,fontFamily:"'DM Sans'"}}/>{lMulti.length>1&&<Btn variant="ghost" size="sm" onClick={()=>setLMulti(x=>x.filter((_,j)=>j!==i))}><X size={12}/></Btn>}</div>)}<Btn variant="secondary" size="sm" onClick={()=>setLMulti(x=>[...x,todayStr()])}><Plus size={11}/> Add</Btn></div>}
              <div style={{fontSize:11,color:tk.textM,marginTop:6}}>Days: <strong style={{color:tk.gold}}>{getLDates().length}</strong></div>
            </div>
            <Inp label="Reason *" value={lReason} onChange={setLReason} type="textarea" placeholder="Reason for leave..."/>
            <Btn full variant="primary" onClick={subLeave}><Send size={13}/> Submit</Btn>
          </>)}
          {tab==="correction"&&(<>
            <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:14}}>Attendance Correction</div>
            <Inp label="Date" value={corrF.date} onChange={v=>setCorrF(f=>({...f,date:v}))} type="date"/>
            <Inp label="Correct IN" value={corrF.inTime} onChange={v=>setCorrF(f=>({...f,inTime:v}))} type="time"/>
            <Inp label="Correct OUT" value={corrF.outTime} onChange={v=>setCorrF(f=>({...f,outTime:v}))} type="time"/>
            <Inp label="Reason (required)" value={corrF.reason} onChange={v=>setCorrF(f=>({...f,reason:v}))} type="textarea" placeholder="Explain why correction is needed..."/>
            <Btn full variant="primary" onClick={subCorr}><Send size={13}/> Submit</Btn>
          </>)}
          {tab==="advance"&&(<>
            <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:14}}>Advance Salary</div>
            <div style={{padding:"10px 12px",background:tk.blueBg,borderRadius:8,fontSize:12,color:tk.blue,marginBottom:14}}>Monthly salary: <strong>{fmtPKR(calcTotal(user.salary))}</strong><br/>Request full month or installments.</div>
            <div style={{marginBottom:14}}>
              <div style={{fontSize:12,fontWeight:500,color:tk.textS,marginBottom:8}}>Advance Type</div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={()=>setAdvF(f=>({...f,type:"full"}))} style={{flex:1,padding:"10px",borderRadius:10,border:`1.5px solid ${advF.type==="full"?tk.gold:tk.border}`,background:advF.type==="full"?tk.goldBg:"transparent",color:advF.type==="full"?tk.gold:tk.textS,fontSize:12,cursor:"pointer",fontFamily:"'DM Sans'",fontWeight:advF.type==="full"?600:400}}>💰 Full Month<br/><span style={{fontSize:10}}>Deducted next salary</span></button>
                {allowInstallments&&<button onClick={()=>setAdvF(f=>({...f,type:"installment"}))} style={{flex:1,padding:"10px",borderRadius:10,border:`1.5px solid ${advF.type==="installment"?tk.gold:tk.border}`,background:advF.type==="installment"?tk.goldBg:"transparent",color:advF.type==="installment"?tk.gold:tk.textS,fontSize:12,cursor:"pointer",fontFamily:"'DM Sans'",fontWeight:advF.type==="installment"?600:400}}>📅 Installments<br/><span style={{fontSize:10}}>Monthly deductions</span></button>}
              </div>
            </div>
            <Inp label="Amount (PKR)" value={advF.amount} onChange={v=>setAdvF(f=>({...f,amount:v}))} type="number" placeholder="e.g. 30000"/>
            {Number(advF.amount)>calcTotal(user.salary)&&<div style={{fontSize:12,color:tk.orange,marginTop:-10,marginBottom:10}}>⚠ Exceeds salary — overflow deducts next month</div>}
            {advF.type==="installment"&&<Inp label="Monthly Deduction (PKR)" value={advF.monthly} onChange={v=>setAdvF(f=>({...f,monthly:v}))} type="number" placeholder={`Max: ${fmtPKR(calcTotal(user.salary))}`}/>}
            <Inp label="Reason" value={advF.reason} onChange={v=>setAdvF(f=>({...f,reason:v}))} type="textarea" placeholder="Reason for advance..."/>
            <Btn full variant="primary" onClick={subAdv}><Send size={13}/> Submit</Btn>
          </>)}
          {tab==="history"&&(<>
            <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:10}}>Request Old Records</div>
            <div style={{padding:"10px 12px",background:tk.orangeBg,borderRadius:8,fontSize:12,color:tk.orange,marginBottom:14}}>🔒 Last 3 months are freely accessible. For older records, request admin approval.</div>
            <Inp label="Records From (date)" value={histReq.from} onChange={v=>setHistReq(f=>({...f,from:v}))} type="date"/>
            <Inp label="Reason" value={histReq.reason} onChange={v=>setHistReq(f=>({...f,reason:v}))} type="textarea" placeholder="Why do you need older records?"/>
            <Btn full variant="primary" onClick={subHist}><Send size={13}/> Request Access</Btn>
          </>)}
        </Card>
        <div>
          <div style={{fontWeight:600,fontSize:14,color:tk.text,marginBottom:10}}>History</div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {(tab==="leave"?myLeaves:tab==="correction"?myCorr:tab==="advance"?myAdv:myHist).length===0
              ?<Card><Empty icon={FileText} title="No requests yet"/></Card>
              :(tab==="leave"?myLeaves:tab==="correction"?myCorr:tab==="advance"?myAdv:myHist).slice().reverse().map(item=>(
                <Card key={item.id} style={{padding:14}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
                    <div style={{flex:1}}>
                      {tab==="leave"&&<div style={{fontSize:13,color:tk.textS,marginBottom:2}}>{item.dateFrom===item.dateTo?fmtDate(item.dateFrom):`${fmtDate(item.dateFrom)} → ${fmtDate(item.dateTo)}`} · <strong>{(item.dates||[]).length}d</strong></div>}
                      {tab==="correction"&&<div style={{fontSize:13,color:tk.textS,marginBottom:2}}>{fmtDate(item.date)} · {fmt12(item.reqIn)} – {fmt12(item.reqOut)}</div>}
                      {tab==="advance"&&staffAdvanceHistoryItem(item,tk,fmtPKR,Badge,Btn,(id)=>staffConfirmAdvance(updateStore,refresh,{user,requestId:id,accept:true,fmtPKR}),(id)=>staffConfirmAdvance(updateStore,refresh,{user,requestId:id,accept:false,fmtPKR}))}
                      {tab==="history"&&<div style={{fontSize:13,color:tk.textS,marginBottom:2}}>From: {fmtDate(item.dateFrom)}</div>}
                      <div style={{fontSize:12,color:tk.textM}}>{item.reason}</div>
                    </div>
                    {tab==="advance"?<AdvanceStatusBadge status={item.status||item.workflowStatus} tk={tk}/>:<Badge color={item.status==="pending"?"orange":item.status==="approved"?"green":"red"}>{item.status}</Badge>}
                  </div>
                </Card>
              ))
            }
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App(){
  const [dark,setDark]=useState(false);
  const [store,setStore]=useState(null);
  const [user,setUser]=useState(null);
  const [bootReady,setBootReady]=useState(false);
  const [bootWarn,setBootWarn]=useState(null);
  const [needsSetup,setNeedsSetup]=useState(false);
  const [adminPage,setAdminPage]=useState("dashboard");
  const [staffPage,setStaffPage]=useState("dashboard");
  const [staffReqTab,setStaffReqTab]=useState("leave");
  const setStaffPageNav=(page,reqTab)=>{setStaffPage(page);if(reqTab)setStaffReqTab(reqTab);};
  const [navTarget,setNavTarget]=useState(null);
  const [holidayPopup,setHolidayPopup]=useState(null);
  const goToNav=(target)=>{setAdminPage(target.page);setNavTarget(target);};
  const clearNavTarget=()=>setNavTarget(null);
  const navCtx={navTarget,goTo:goToNav,clearNav:clearNavTarget};
  const [adminTour,setAdminTour]=useState(false);
  const [staffTour,setStaffTour]=useState(false);
  const tk=T(dark);

  useEffect(()=>{injectFonts();},[]);
  useEffect(()=>{injectStyles(dark);document.documentElement.classList.toggle("dark",dark);},[dark]);

  useEffect(()=>{
    let unsubRt;
    let unsubAuth;
    (async()=>{
      try{
        setNeedsSetup(await checkNeedsAdminSetup());
        const sessionUser=await getSessionUser();
        if(sessionUser){
          setUser(sessionUser);
          const s=await initStore();
          setStore(s);
          setBootWarn(getStoreBootstrapError());
          unsubRt=subscribeStoreUpdates((next)=>setStore({...next}));
        }else{
          setStore(resetStoreCache());
        }
        unsubAuth=onAuthStateChange(async(_evt,appUser)=>{
          setUser(appUser);
          if(appUser){
            const fresh=await initStore(true);
            setStore(fresh);
            setBootWarn(getStoreBootstrapError());
            setNeedsSetup(false);
          }else{
            setStore(resetStoreCache());
            setNeedsSetup(await checkNeedsAdminSetup());
          }
        });
      }finally{
        setBootReady(true);
      }
    })();
    return ()=>{unsubRt?.();unsubAuth?.data?.subscription?.unsubscribe?.();};
  },[]);

  // Holiday check for admin
  useEffect(()=>{
    if(!user||user.role!=="admin"||!store) return;
    const st=store;
    const resolved=new Set(st.resolvedHolidays||[]);
    const upcoming=PK_HOLIDAYS.find(h=>{const d=new Date(h.date),diff=(d-new Date())/(1000*60*60*24);return diff>0&&diff<=7&&!resolved.has(h.date);});
    if(upcoming) setHolidayPopup(upcoming);
  },[user]);

  const resolveHoliday=(holiday,markOff)=>{
    updateStore(s=>{if(!s.resolvedHolidays)s.resolvedHolidays=[];s.resolvedHolidays.push(holiday.date);if(markOff&&!s.offDays.find(o=>o.date===holiday.date))s.offDays.push({id:uid(),date:holiday.date,name:holiday.name,scope:"all",userIds:[]});return s;});
    setStore(getStore());setHolidayPopup(null);
  };

  const refresh=()=>setStore(getStore());

  const login=async(email,password)=>{
    pendingActionsSnoozed=false;
    const res=await signInWithEmail(email,password);
    if(!res.ok)return res;
    const s=await initStore(true);
    setStore(s);
    setBootWarn(getStoreBootstrapError());
    setNeedsSetup(false);
    setUser(res.user);
    updateStore(s=>{
      s.auditLog.unshift({id:uid(),userId:res.user.id,action:"Login",detail:`${res.user.name} logged in`,ts:new Date().toISOString(),ip:"127.0.0.1"});
      if(!s.loginActivity)s.loginActivity=[];
      s.loginActivity.unshift({id:uid(),userId:res.user.id,email:res.user.email,role:res.user.role,ts:new Date().toISOString(),ip:"127.0.0.1",device:getDeviceMeta().device});
      pushEnterpriseAudit(s,{module:"auth",action:"login",changedBy:res.user.id,role:resolveEnterpriseRole(res.user),entityId:res.user.id});
      return s;
    });
    await flushStore();
    refresh();
    if(!res.user.tourDone){
      if(res.user.role==="admin"||res.user.role==="manager")setAdminTour(true);
      else setStaffTour(true);
    }
    return{ok:true,user:res.user};
  };

  const registerAdmin=async({email,password,name})=>{
    const res=await signUpAdmin({email,password,name});
    if(!res.ok)return res;
    if(res.needsEmailConfirm)return{ok:true,needsEmailConfirm:true};
    return login(email,password);
  };

  const logout=async()=>{
    if(user){
      updateStore(s=>{s.auditLog.unshift({id:uid(),userId:user.id,action:"Logout",detail:`${user.name} logged out`,ts:new Date().toISOString(),ip:"127.0.0.1"});return s;});
      await flushStore();
    }
    await authSignOut();
    pendingActionsSnoozed=false;
    setUser(null);
    setAdminPage("dashboard");setStaffPage("dashboard");setStaffReqTab("leave");
    setStore(resetStoreCache());
    setNeedsSetup(await checkNeedsAdminSetup());
  };

  const themeCtx={dark,isDark:dark,toggleTheme:()=>setDark(d=>!d),tk};
  const authCtx={
    user,login,logout,registerAdmin,
    isAdmin:user?.role==="admin",
    isManager:user?.role==="manager",
    isStaff:user?.role==="staff",
    enterpriseRole:user?resolveEnterpriseRole(user):null,
    canDo:(perm)=>{
      if(!user) return false;
      if(user.role==="admin") return true;
      const actionMap={canApproveLeave:"approve",canViewReports:"export",canEditAttendance:"edit",canReviewAdvance:"review",canApproveAdvanceFinance:"advance_approve",canViewSalary:"view_salary",canAddStaff:"add_staff",canDeleteStaff:"delete_staff",canBroadcast:"broadcast",canViewAudit:"audit"};
      const action=actionMap[perm]||perm;
      if(canEnterprisePerm(user,action,null,store)) return true;
      if(user.role==="manager"&&user.managerPerms) return !!user.managerPerms[perm];
      return false;
    },
  };
  const storeCtx={store,refresh,saving:isStoreSaving()};

  if(!bootReady||!store){
    return(
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:tk.bg,flexDirection:"column",gap:12}}>
        <div style={{width:36,height:36,border:`3px solid ${tk.border}`,borderTopColor:tk.gold,borderRadius:"50%",animation:"spin 0.8s linear infinite"}}/>
        <p style={{fontSize:14,color:tk.textS}}>Loading Alvin Desk…</p>
      </div>
    );
  }

  return(
    <ThemeCtx.Provider value={themeCtx}>
      <ToastProvider tk={tk}>
        <AuthCtx.Provider value={authCtx}>
          <StoreCtx.Provider value={storeCtx}>
            <NavTargetCtx.Provider value={navCtx}>
            {bootWarn&&(
              <div style={{position:"fixed",top:0,left:0,right:0,zIndex:9998,padding:"8px 16px",background:tk.redBg,borderBottom:`1px solid ${tk.red}`,fontSize:12,color:tk.red,textAlign:"center"}}>
                Database: {bootWarn} — Run supabase/migrations/001_relational_schema.sql in Supabase SQL Editor.
              </div>
            )}
            <div style={{position:"fixed",bottom:56,left:12,zIndex:40,padding:"4px 10px",borderRadius:20,background:tk.greenBg,border:`1px solid ${tk.green}`,fontSize:10,color:tk.green,fontWeight:600}}>● Supabase Cloud</div>
            {holidayPopup&&user?.role==="admin"&&<HolidayPopup holiday={holidayPopup} onResolve={resolveHoliday}/>}
            {!user&&<LoginPage needsSetup={needsSetup}/>}
            {user&&(user.role==="admin"||user.role==="manager")&&<AdminLayout page={adminPage} setPage={setAdminPage} showTour={adminTour} setShowTour={setAdminTour}/>}
            {user&&user.role==="staff"&&<StaffLayout page={staffPage} setPage={setStaffPageNav} requestsTab={staffReqTab} showTour={staffTour} setShowTour={setStaffTour}/>}
            </NavTargetCtx.Provider>
          </StoreCtx.Provider>
        </AuthCtx.Provider>
      </ToastProvider>
    </ThemeCtx.Provider>
  );
}
